import androidx.core.app.JobIntentService
import java.util.concurrent.atomic.AtomicBoolean

class BackgroundTaskService : JobIntentService() {
    companion object {
        private const val TAG = "BackgroundTaskService"
        private const val ACTION_SYNC = "com.example.systemoptimization.action.SYNC"
        private const val ACTION_CLEANUP = "com.example.systemoptimization.action.CLEANUP"
        private const val EXTRA_TASK_ID = "task_id"
        private const val EXTRA_USER_ID = "user_id"
        private const val EXTRA_DATA = "data"
        private const val PERMISSION_BACKGROUND_TASK = "com.example.systemoptimization.permission.BACKGROUND_TASK"
        private const val JOB_ID = 1001
        
        fun enqueueWork(context: Context, intent: Intent) {
            enqueueWork(context, BackgroundTaskService::class.java, JOB_ID, intent)
        }
