    private val isProcessing = AtomicBoolean(false)

    override fun onBind(intent: Intent): IBinder? = null

    override fun onHandleWork(intent: Intent) {
        if (!validateCaller(intent)) {
            Log.w(TAG, "Invalid caller attempted to access service")
            return
        }

        if (!validateIntentData(intent)) {
            Log.w(TAG, "Invalid intent data received")
            return
        }

        if (isProcessing.getAndSet(true)) {
            Log.w(TAG, "Service already processing a task")
            return
        }

        try {
            val action = intent.action
            when (action) {
                ACTION_SYNC -> handleSyncTask(intent)
                ACTION_CLEANUP -> handleCleanupTask(intent)
                else -> Log.w(TAG, "Unknown action: $action")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing task", e)
        } finally {
            isProcessing.set(false)
        }
