        if (callerPackage == null) return false
        
        val packageManager = packageManager
        val permissionInfo = try {
            packageManager.getPermissionInfo(PERMISSION_BACKGROUND_TASK, 0)
            true
        } catch (e: PackageManager.NameNotFoundException) {
            false
        }
        
        if (!permissionInfo) return false
        
        return packageManager.checkPermission(PERMISSION_BACKGROUND_TASK, callerPackage) == 
               PackageManager.PERMISSION_GRANTED
    }

    private fun validateIntentData(intent: Intent): Boolean {
        val action = intent.action ?: return false
        
        if (action != ACTION_SYNC && action != ACTION_CLEANUP) {
            return false
        }

        val taskId = intent.getStringExtra(EXTRA_TASK_ID)
